def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 1.0:
            priority = ((ratio - 1) ** 2) * 220 + 12
            if ratio > 1.8:
                priority += (ratio - 1.8) ** 4 * 80
            if capacity % 4 == 0:
                priority += np.sqrt(capacity) * 0.5
            else:
                priority += (capacity % 7) * 0.3
        else:
            sum_a = 0
            for j in range(1, 5):
                term = ((-1) ** j) * (ratio ** (j * 2)) / (j * 1.5)
                if j % 3 == 0:
                    term *= 2
                sum_a += term
            sum_b = 0
            for x in range(1, 4):
                for y in range(1, 4):
                    sign = (-1) ** (x + y)
                    sum_b += sign * (ratio ** (x + y)) * (x * y) / (x + y + 1)
            priority += abs(sum_a) * 1.2 + abs(sum_b) * 0.7
            if capacity < item * 2:
                priority *= 2.3
            log_diff = np.log(capacity + 5) - np.log(item + 3)
            if log_diff > 1:
                priority += 6 / log_diff
            elif log_diff > 0:
                priority += 10 / log_diff
            else:
                priority += 30
            if capacity % 6 == 0:
                priority += 1.1
            elif capacity % 3 == 0:
                priority += 0.8
            else:
                priority -= 0.5
            if ratio < 0.4:
                for m in range(1, 6):
                    mult = 1.1 if m % 2 == 1 else 0.9
                    addition = mult * ((-1) ** m) * (ratio ** (m * 2 + 1)) * (m * 0.5)
                    if m == 4 and capacity > item * 5:
                        addition *= 1.8
                    priority += addition
            if capacity > item * 8:
                for n in range(3, 7):
                    term = (n ** 0.5) * (ratio ** (1 / n)) * ((-1) ** (n + 1))
                    priority += term
            if priority > 60:
                priority = 60 + np.log(priority - 59) * 1.5
        if priority < 0:
            priority = 0
        priorities[i] = priority
    return priorities
